query:
DELETE FROM purchase_requests 
WHERE id IN (
  SELECT id FROM (
    SELECT id,
           ROW_NUMBER() OVER (PARTITION BY prNumber, organizationId, operatingUnitId ORDER BY id) as rn
    FROM purchase_requests
  ) t
  WHERE rn > 1
);

